#include "lex.hpp"
#include <iostream>
#include <cstdlib>

void
print_token();

namespace lex {

static const char* kTokenNames[] = {
  "identifier",       // IDENTIFIER
  "numeric_constant", // CONSTANT
  "string_literal",   // STRING_LITERAL
  "int",              // INT
  "return",           // RETURN
  "if",               // IF
  "else",             // ELSE
  "while",            // WHILE
  "break",            // BREAK
  "continue",         // CONTINUE
  "void",             // VOID
  "const",            // CONST
  "l_brace",          // L_BRACE
  "r_brace",          // R_BRACE
  "l_square",         // L_SQUARE
  "r_square",         // R_SQUARE
  "l_paren",          // L_PAREN
  "r_paren",          // R_PAREN
  "semi",             // SEMI
  "comma",            // COMMA
  "equal",            // EQUAL
  "equalequal",       // EQUALEQUAL
  "plus",             // PLUS
  "minus",            // MINUS
  "star",             // STAR
  "slash",            // SLASH
  "percent",          // PERCENT
  "exclaim",          // EXCLAIM
  "exclaimequal",     // EXCLAIMEQUAL
  "ampamp",           // AMPAMP
  "pipepipe",         // PIPEPIPE
  "less",             // LESS
  "greater",          // GREATER
  "lessequal",        // LESSEQUAL
  "greaterequal",     // GREATEREQUAL
  "amp",              // AMP
  "pipe",             // PIPE
  "caret",            // CARET
  "tilde",            // TILDE
  "lshift",           // LSHIFT
  "rshift",           // RSHIFT
  "plusequal",        // PLUSEQUAL
  "minusequal",       // MINUSEQUAL
  "starequal",        // STAREQUAL
  "slashequal",       // SLASHEQUAL
  "percentequal",     // PERCENTEQUAL
  "ampequal",         // AMPEQUAL
  "pipeequal",        // PIPEEQUAL
  "caretequal",       // CARETEQUAL
  "lshiftequal",      // LSHIFTEQUAL
  "rshiftequal",      // RSHIFTEQUAL
  "plusplus",         // PLUSPLUS
  "minusminus",       // MINUSMINUS
  "arrow",            // ARROW
  "question",         // QUESTION
  "colon",            // COLON
  "dot",              // DOT
  "ellipsis",         // ELLIPSIS
};

const char*
id2str(Id id)
{
  static char sCharBuf[2] = { 0, 0 };
  if (id == Id::YYEOF) {
    return "eof";
  }
  else if (id < Id::IDENTIFIER) {
    sCharBuf[0] = char(id);
    return sCharBuf;
  }
  return kTokenNames[int(id) - int(Id::IDENTIFIER)];
}

G g;

int
come(int tokenId, const char* yytext, int yyleng, int yylineno)
{
  g.mId = Id(tokenId);
  g.mText = { yytext, std::size_t(yyleng) };
  g.mLine = yylineno;

  print_token();
  g.mStartOfLine = false;
  g.mLeadingSpace = false;

  return tokenId;
}

void
handle_line_marker(const char* yytext, int yyleng)
{
  // Parse line marker: # linenum "filename" [flags...]
  // Example: # 1 "./basic/000_main.sysu.c"
  // Example: # 1 "<built-in>" 1
  // Example: # 1 "/path/file.sysu.c" 2

  std::string_view sv(yytext, yyleng);

  // Skip the '#' and whitespace
  size_t pos = 1;
  while (pos < sv.size() && (sv[pos] == ' ' || sv[pos] == '\t'))
    ++pos;

  // Parse line number
  int lineNum = 0;
  while (pos < sv.size() && sv[pos] >= '0' && sv[pos] <= '9') {
    lineNum = lineNum * 10 + (sv[pos] - '0');
    ++pos;
  }

  // Skip whitespace
  while (pos < sv.size() && (sv[pos] == ' ' || sv[pos] == '\t'))
    ++pos;

  // Parse filename (quoted string)
  if (pos < sv.size() && sv[pos] == '"') {
    ++pos;
    size_t start = pos;
    while (pos < sv.size() && sv[pos] != '"') {
      if (sv[pos] == '\\' && pos + 1 < sv.size())
        ++pos; // skip escaped char
      ++pos;
    }
    g.mFile = std::string(sv.substr(start, pos - start));
    ++pos; // skip closing quote
  }

  // Update line number
  if (lineNum > 0) {
    g.mLine = lineNum;
  }

  // After a line marker, the next token is at start of line
  g.mStartOfLine = true;
  g.mLeadingSpace = false;
  g.mColumn = 1;
}

} // namespace lex
